package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseTest {

    private File fileMock;
    private Charset charset;
    private CSVFormat formatMock;
    private InputStreamReader inputStreamReaderMock;

    @BeforeEach
    void setup() {
        fileMock = mock(File.class);
        charset = Charset.defaultCharset();
        formatMock = mock(CSVFormat.class);
    }

    @Test
    void parse_withValidFile_shouldReturnCSVParser() throws IOException {
        // Mock FileInputStream construction and InputStreamReader construction
        try (MockedConstruction<FileInputStream> fisMock = Mockito.mockConstruction(FileInputStream.class);
             MockedConstruction<InputStreamReader> isrMock = Mockito.mockConstruction(InputStreamReader.class,
                (mock, context) -> {
                    // no additional stubbing required
                })) {

            CSVParser parser = CSVParser.parse(fileMock, charset, formatMock);

            assertNotNull(parser);
            assertEquals(formatMock, parser.format);
            // The parser is constructed with InputStreamReader and format
        }
    }

    @Test
    void parse_nullFile_shouldThrowNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, charset, formatMock);
        });
        assertEquals("file", ex.getMessage());
    }

    @Test
    void parse_nullFormat_shouldThrowNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(fileMock, charset, null);
        });
        assertEquals("format", ex.getMessage());
    }
}
